package views

component Greeting(name string, count int) {
	<p>Hello, { name }! You have { count } messages.</p>
}

package views

component FullName(first string, last string) {
	<div>
		{{ full := first + " " + last }}
		<span>{ full }</span>
	</div>
}

package views

component Tracker() {
	<script>
		const threshold = 5;
		if (count < threshold) { track("below"); }
	</script>
}

package views

