import "github.com/gsxhq/gsx"

type Props struct {
	Variant  string
	Children gsx.Node
	Attrs    gsx.Attrs
}

component Button(p Props) {
	<button class={ "btn", p.Variant } { p.Attrs... }>{ p.Children }</button>
